### 3.3 聊天页
```tsx
// pages/chat.tsx 或 app/chat/page.tsx
import { useMemo, useState } from "react";
import { useRouter } from "next/router";
import { agents } from "../agents";

type Msg = { role: "user" | "assistant"; content: string };

export default function ChatPage() {
  const router = useRouter();
  const agentId = (router.query.agent as string) || "polish";

  const agent = useMemo(
    () => agents.find(a => a.id === agentId) ?? agents[0],
    [agentId]
  );

  const [input, setInput] = useState("");
  const [msgs, setMsgs] = useState<Msg[]>([]);
  const [loading, setLoading] = useState(false);

  async function send() {
    if (!input.trim() || loading) return;
    const userMsg: Msg = { role: "user", content: input.trim() };
    const nextMsgs = [...msgs, userMsg];
    setMsgs(nextMsgs);
    setInput("");
    setLoading(true);

    const res = await fetch("/api/chat", {
      method: "POST",
      headers: { "Content-Type": "application/json" },
      body: JSON.stringify({
        agentId: agent.id,
        mode: agent.mode,
        message: userMsg.content,
        history: msgs, // 只传之前的对话
      }),
    });

    const data = await res.json();
    setMsgs([...nextMsgs, { role: "assistant", content: data.reply }]);
    setLoading(false);
  }

  return (
    <div className="wrap">
      <aside className="side">
        <div className="agent">
          <img className="avatar" src={agent.avatar} />
          <div>
            <div className="title">{agent.title}</div>
            <div className="desc">{agent.desc}</div>
          </div>
        </div>
        <button className="back" onClick={() => router.push("/agents")}>
          返回角色选择
        </button>
      </aside>

      <main className="main">
        <div className="chat">
          {msgs.length === 0 && (
            <div className="empty">
              <div className="hint">输入你的需求、粘贴文本或审稿意见开始对话。</div>
              {agent.id === "polish" && (
                <div className="hint2">建议提供：目标期刊/会议、段落原文、希望保留的术语表。</div>
              )}
            </div>
          )}

          {msgs.map((m, i) => (
            <div key={i} className={`msg ${m.role}`}>
              <div className="bubble">{m.content}</div>
            </div>
          ))}
          {loading && <div className="msg assistant"><div className="bubble">正在生成…</div></div>}
        </div>

        <div className="inputBar">
          <textarea
            value={input}
            onChange={e => setInput(e.target.value)}
            placeholder="请输入…（Shift+Enter 换行，Enter 发送）"
            onKeyDown={e => {
              if (e.key === "Enter" && !e.shiftKey) {
                e.preventDefault();
                send();
              }
            }}
          />
          <button onClick={send} disabled={loading}>发送</button>
        </div>
      </main>

      <style jsx>{`
        .wrap{display:grid;grid-template-columns:280px 1fr;gap:16px;max-width:1200px;margin:0 auto;padding:20px;}
        .side{border:1px solid #E6E8EC;border-radius:14px;background:#fff;padding:14px;height:calc(100vh - 40px);position:sticky;top:20px;}
        .agent{display:flex;gap:12px;align-items:center;margin-bottom:12px;}
        .avatar{width:46px;height:46px;border-radius:999px;border:1px solid #eee;}
        .title{font-weight:700;}
        .desc{font-size:13px;color:#667085;margin-top:2px;}
        .back{margin-top:10px;width:100%;border:1px solid #E6E8EC;background:#fff;border-radius:10px;padding:10px;cursor:pointer;}
        .main{border:1px solid #E6E8EC;border-radius:14px;background:#fff;display:flex;flex-direction:column;height:calc(100vh - 40px);}
        .chat{flex:1;overflow:auto;padding:16px;}
        .empty{border:1px dashed #E6E8EC;border-radius:12px;padding:14px;color:#667085;}
        .hint{font-size:14px;}
        .hint2{font-size:13px;margin-top:8px;}
        .msg{display:flex;margin:10px 0;}
        .msg.user{justify-content:flex-end;}
        .msg.assistant{justify-content:flex-start;}
        .bubble{
          max-width:78%;
          white-space:pre-wrap;
          border-radius:14px;
          padding:10px 12px;
          border:1px solid #E6E8EC;
          background:#F9FAFB;
          color:#101828;
          font-size:14px;
          line-height:1.55;
        }
        .msg.user .bubble{background:#111827;color:#fff;border-color:#111827;}
        .inputBar{display:flex;gap:10px;padding:12px;border-top:1px solid #E6E8EC;}
        textarea{flex:1;resize:none;height:46px;border:1px solid #E6E8EC;border-radius:12px;padding:10px 12px;outline:none;font-size:14px;}
        button{width:90px;border-radius:12px;border:1px solid #111827;background:#111827;color:#fff;cursor:pointer;}
        button:disabled{opacity:.6;cursor:not-allowed;}
        @media (max-width:920px){.wrap{grid-template-columns:1fr;}.side{position:relative;height:auto;}}
      `}</style>
    </div>
  );
}
```

> 如果你前端不是 Next.js，而是 Vue/纯 HTML，我也可以按你技术栈重写同样结构。

---

## 4）前后端对接注意点（避免踩坑）

1. **history 的长度控制**：建议只保留最近 N 轮（如 10-20 条），避免上下文过长。
2. **plan 模式**：前端如果 `agent.mode === 'plan'`，可在右侧增加“时间表渲染组件”，优先使用后端返回的 `plan`（已解析 JSON）。
3. **头像资源**：放在前端 `public/avatars/*.png`，或由后端返回 URL。
4. **安全性**：不要把 API Key 写死在代码仓库；用环境变量 + 后端调用（前端永不直连 Moonshot）。
5. **“页面风格与附件一致”**：我需要附件截图/链接，才能把字体、色板、阴影、圆角、间距、按钮样式、卡片布局等做成一致。

---

## 5）我需要你补充 3 个信息，我就能把“最终成品”给你整合成一个可运行项目

1. 你的前端技术栈：**Next.js / React / Vue / 原生 HTML**？  
2. 附件里的页面风格截图（或 Figma 链接）。  
3. 你希望对话入口是：
   - A. 单独一个“角色选择页”  
   - B. 聊天页左侧栏直接切换角色（类似客服工作台）

把截图发我后，我可以按你的附件风格把上面的 UI 完整复刻，并把路由、接口、角色配置、头像资源目录结构一起整理成可直接 `npm run dev` + `uvicorn app:app` 跑起来的工程。

