## 1）后端：增加一个 HTTP 接口（FastAPI），复用你现有 get_kimi_response

你现有 `get_kimi_response(input_text, mode)` 是“单轮”。要做聊天界面，推荐新增一个 `get_kimi_chat(message, mode, history)`：  
- history 为可选：`[{role: "user"|"assistant", content: "..."}]`
- 仍然走你 `prompts.py` 里定义的 `*_PROMPT`

### 1.1 `server.py`（新增一个文件即可）
```python
# server.py
import os
import json
import re
from typing import Any, Dict, List, Optional
from fastapi import FastAPI
from pydantic import BaseModel
from openai import OpenAI
from prompts import RESPONSE_PROMPT, PLAN_PROMPT, POLISH_PROMPT, REBUTTAL_PROMPT, IDEA_PROMPT

client = OpenAI(
    api_key=os.environ.get("MOONSHOT_API_KEY"),   # <- 改成环境变量
    base_url="https://api.moonshot.cn/v1"
)

app = FastAPI()

def sanitize_and_parse(raw: str):
    cleaned = re.sub(r'^```json\s*|\s*```$', '', raw.strip(), flags=re.I).strip()
    if not cleaned:
        raise ValueError("输入为空或仅含代码块标记")
    data = json.loads(cleaned)
    if isinstance(data, list):
        for task in data:
            if isinstance(task, dict):
                task.setdefault("状态", "未开始")
                task.setdefault("颜色", "blue")
    return data

def pick_system_prompt(mode: str) -> str:
    if mode == "plan":
        return PLAN_PROMPT
    if mode == "response":
        return RESPONSE_PROMPT
    if mode == "polish":
        return POLISH_PROMPT
    if mode == "rebuttal":
        return REBUTTAL_PROMPT
    if mode == "idea":
        return IDEA_PROMPT
    raise ValueError("Unhandled mode identifier.")

def get_kimi_chat(message: str, mode: str, history: Optional[List[Dict[str, str]]] = None) -> Dict[str, Any]:
    system_content = pick_system_prompt(mode)

    messages = [{"role": "system", "content": system_content}]
    if history:
        # 只接受 user/assistant，避免前端塞 system
        for m in history[-20:]:
            if m.get("role") in ["user", "assistant"] and isinstance(m.get("content"), str):
                messages.append({"role": m["role"], "content": m["content"]})

    messages.append({"role": "user", "content": message})

    completion = client.chat.completions.create(
        model="kimi-k2-turbo-preview",
        messages=messages,
        temperature=0.2,
    )
    reply = completion.choices[0].message.content

    resp: Dict[str, Any] = {
        "status": "success",
        "mode": mode,
        "reply": reply
    }

    # plan 模式：可选返回解析后的 JSON
    if mode == "plan":
        try:
            resp["plan"] = sanitize_and_parse(reply)
        except Exception:
            resp["plan"] = None

    return resp


class ChatReq(BaseModel):
    mode: str               # response | plan | polish | rebuttal | idea
    message: str
    history: Optional[List[Dict[str, str]]] = None


@app.post("/api/chat")
def chat(req: ChatReq):
    try:
        return get_kimi_chat(req.message, req.mode, req.history)
    except Exception as e:
        return {"status": "error", "error": str(e)}
```

启动：
```bash
export MOONSHOT_API_KEY="你的key"
uvicorn server:app --reload --port 8000
```

