### 2.2 聊天页 `ChatView.jsx`
```jsx
import { useEffect, useMemo, useRef, useState } from "react";
import { useLocation, useNavigate, useParams } from "react-router-dom";
import { ArrowLeft, Loader2 } from "lucide-react";
import BrandMark from "../components/BrandMark.jsx";

const agentMeta = {
  polish: { title: "论文语言润色", avatar: "/static/agents/polish.png" },
  rebuttal: { title: "审稿人回复建议", avatar: "/static/agents/rebuttal.png" },
  idea: { title: "论文思路打磨", avatar: "/static/agents/idea.png" },
  plan: { title: "投稿时间规划", avatar: "/static/agents/plan.png" },
  response: { title: "通用投稿助手", avatar: "/static/agents/default.png" },
};

export default function ChatView() {
  const { mode } = useParams(); // polish/rebuttal/idea/plan/response
  const navigate = useNavigate();
  const location = useLocation();

  const agent = useMemo(() => {
    return location.state?.agent ?? agentMeta[mode] ?? agentMeta.response;
  }, [location.state, mode]);

  const [input, setInput] = useState("");
  const [error, setError] = useState("");
  const [loading, setLoading] = useState(false);
  const [messages, setMessages] = useState([]); // {role:'user'|'assistant', content:string}[]
  const bottomRef = useRef(null);

  useEffect(() => {
    bottomRef.current?.scrollIntoView({ behavior: "smooth" });
  }, [messages, loading]);

  const send = async () => {
    setError("");
    if (!input.trim() || loading) return;

    const userMsg = { role: "user", content: input.trim() };
    const next = [...messages, userMsg];
    setMessages(next);
    setInput("");
    setLoading(true);

    try {
      const res = await fetch("/api/chat", {
        method: "POST",
        credentials: "include",
        headers: { "Content-Type": "application/json" },
        body: JSON.stringify({
          mode,
          message: userMsg.content,
          history: messages, // 传旧消息即可
        }),
      });
      const data = await res.json();
      if (!res.ok || data.status === "error") {
        throw new Error(data?.error || `HTTP ${res.status}`);
      }
      setMessages([...next, { role: "assistant", content: data.reply }]);
    } catch (e) {
      setError(e.message || "请求失败");
    } finally {
      setLoading(false);
    }
  };

  return (
    <div className="relative isolate flex min-h-screen flex-col overflow-hidden px-4 py-8 sm:px-8 lg:px-12">
      <div className="pointer-events-none absolute inset-0 -z-10">
        <div className="absolute -top-44 left-0 h-80 w-80 rounded-full bg-[#b9c6ff]/40 blur-3xl sm:h-96 sm:w-96" />
        <div className="absolute bottom-[-18rem] right-[-10rem] h-[28rem] w-[28rem] rounded-full bg-[#ffe5f8]/40 blur-3xl" />
        <div className="absolute inset-x-0 top-1/2 h-32 -translate-y-1/2 bg-gradient-to-r from-transparent via-white/60 to-transparent" />
      </div>

      <div className="mx-auto flex w-full max-w-6xl flex-1 flex-col">
        <header className="mb-6 flex items-center justify-between">
          <BrandMark withTagline className="text-[#1a1d2b]" />
          <button
            onClick={() => navigate("/agents")}
            className="inline-flex items-center gap-2 rounded-full border border-white/60 bg-white/70 px-4 py-2 text-xs font-medium text-[#4a5076] shadow-sm backdrop-blur transition hover:border-primary/40 hover:text-primary"
          >
            <ArrowLeft className="h-4 w-4" />
            返回角色选择
          </button>
        </header>

        <section className="grid gap-6 lg:grid-cols-[360px_1fr]">
          <aside className="relative overflow-hidden rounded-3xl border border-white/60 bg-white/85 p-8 shadow-xl shadow-primary/5 backdrop-blur">
            <div className="absolute -top-20 right-0 h-52 w-52 rounded-full bg-primary/10 blur-3xl" />
            <div className="relative z-10 flex items-center gap-4">
              <img src={agent.avatar} className="h-16 w-16 rounded-2xl border border-slate-100 bg-white object-cover shadow-sm" />
              <div>
                <div className="text-xl font-semibold text-[#1f2a55]">{agent.title}</div>
                <div className="mt-2 text-sm leading-relaxed text-[#657095]">
                  当前模式：<span className="font-semibold text-primary">{mode}</span>
                </div>
              </div>
            </div>

            <div className="mt-6 rounded-2xl border border-slate-100/80 bg-slate-50/70 p-4 text-sm leading-relaxed text-[#657095]">
              {mode === "polish" && "建议粘贴原文段落 + 目标期刊/会议 + 是否偏好更正式/更简洁表达。"}
              {mode === "rebuttal" && "建议逐条粘贴审稿意见（可编号），并说明你愿意补充的实验/你认为的关键点。"}
              {mode === "idea" && "建议说明研究问题、数据/实验条件、预期投稿方向与创新点。"}
              {mode === "plan" && "建议提供当前日期、截稿日期、当前进度、目标会议/期刊与任务偏好。"}
            </div>
          </aside>

          <main className="flex min-h-[70vh] flex-col overflow-hidden rounded-3xl border border-white/60 bg-white/90 shadow-2xl shadow-primary/10 backdrop-blur">
            <div className="flex-1 space-y-4 overflow-auto px-6 py-6">
              {messages.length === 0 && (
                <div className="rounded-2xl border border-dashed border-slate-200/80 bg-slate-50/60 p-5 text-sm text-[#657095]">
                  输入内容开始对话。Enter 发送，Shift+Enter 换行。
                </div>
              )}

              {messages.map((m, idx) => (
                <div key={idx} className={`flex ${m.role === "user" ? "justify-end" : "justify-start"}`}>
                  <div
                    className={`max-w-[82%] whitespace-pre-wrap rounded-2xl border px-4 py-3 text-sm leading-relaxed shadow-sm ${
                      m.role === "user"
                        ? "border-primary bg-primary text-white shadow-primary/20"
                        : "border-slate-200/80 bg-white text-[#1a1d2b]"
                    }`}
                  >
                    {m.content}
                  </div>
                </div>
              ))}

              {loading && (
                <div className="flex justify-start">
                  <div className="inline-flex items-center gap-2 rounded-2xl border border-slate-200/80 bg-white px-4 py-3 text-sm text-[#657095]">
                    <Loader2 className="h-4 w-4 animate-spin" />
                    思考中…
                  </div>
                </div>
              )}

              <div ref={bottomRef} />
            </div>

            {error && (
              <div className="mx-6 mb-3 rounded-2xl border border-error/30 bg-error/10 px-4 py-3 text-sm text-error">
                {error}
              </div>
            )}

            <div className="border-t border-slate-200/80 p-4">
              <div className="flex items-end gap-3">
                <textarea
                  value={input}
                  onChange={(e) => setInput(e.target.value)}
                  onKeyDown={(e) => {
                    if (e.key === "Enter" && !e.shiftKey) {
                      e.preventDefault();
                      send();
                    }
                  }}
                  placeholder="请输入…"
                  className="min-h-[3rem] w-full resize-none rounded-2xl border border-slate-200/80 bg-white/70 px-4 py-3 text-sm leading-relaxed text-[#1a1d2b] shadow-inner shadow-slate-200/60 transition focus:border-primary focus:outline-none focus:ring-4 focus:ring-primary/10"
                />
                <button
                  onClick={send}
                  disabled={loading}
                  className="inline-flex h-[3rem] min-w-[7rem] items-center justify-center rounded-2xl bg-primary px-6 text-sm font-semibold text-white shadow-lg shadow-primary/30 transition hover:brightness-105 disabled:opacity-70"
                >
                  发送
                </button>
              </div>
            </div>
          </main>
        </section>
      </div>
    </div>
  );
}
```

### 2.3 路由（React Router）
```jsx
import { BrowserRouter, Routes, Route, Navigate } from "react-router-dom";
import AgentHubView from "./views/AgentHubView.jsx";
import ChatView from "./views/ChatView.jsx";

export default function App() {
  return (
    <BrowserRouter>
      <Routes>
        <Route path="/" element={<Navigate to="/agents" replace />} />
        <Route path="/agents" element={<AgentHubView />} />
        <Route path="/chat/:mode" element={<ChatView />} />
      </Routes>
    </BrowserRouter>
  );
}
```

